package com.example.enterprise.service;

import com.example.enterprise.dto.CreateUserRequest;
import com.example.enterprise.dto.UserResponse;
import com.example.enterprise.model.AppUser;
import com.example.enterprise.repository.AppUserRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
@Transactional
public class UserService {

    private final AppUserRepository appUserRepository;

    public UserService(AppUserRepository appUserRepository) {
        this.appUserRepository = appUserRepository;
    }

    public UserResponse createUser(CreateUserRequest request) {
        if (appUserRepository.existsByUsername(request.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (appUserRepository.existsByEmail(request.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }

        AppUser user = new AppUser(
                request.getUsername(),
                request.getEmail(),
                request.getFullName(),
                request.getPassword()
        );

        AppUser saved = appUserRepository.save(user);
        return new UserResponse(saved.getId(), saved.getUsername(), saved.getEmail(), saved.getFullName(), saved.isActive());
    }

    @Transactional(readOnly = true)
    public UserResponse getUser(Long id) {
        AppUser user = appUserRepository.findById(id)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));
        return new UserResponse(user.getId(), user.getUsername(), user.getEmail(), user.getFullName(), user.isActive());
    }

    @Transactional(readOnly = true)
    public List<UserResponse> listUsers() {
        return appUserRepository.findAll().stream()
                .map(u -> new UserResponse(u.getId(), u.getUsername(), u.getEmail(), u.getFullName(), u.isActive()))
                .toList();
    }

    public void deactivateUser(Long id) {
        AppUser user = appUserRepository.findById(id)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));
        user.setActive(false);
        appUserRepository.save(user);
    }
}

package com.example.enterprise.service;

import com.example.enterprise.dto.CreateTransactionRequest;
import com.example.enterprise.dto.TransactionResponse;
import com.example.enterprise.model.AppUser;
import com.example.enterprise.model.TransactionRecord;
import com.example.enterprise.repository.AppUserRepository;
import com.example.enterprise.repository.TransactionRecordRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.UUID;

@Service
@Transactional
public class TransactionService {

    private final TransactionRecordRepository transactionRecordRepository;
    private final AppUserRepository appUserRepository;

    public TransactionService(TransactionRecordRepository transactionRecordRepository, AppUserRepository appUserRepository) {
        this.transactionRecordRepository = transactionRecordRepository;
        this.appUserRepository = appUserRepository;
    }

    public TransactionResponse createTransaction(CreateTransactionRequest request) {
        if (transactionRecordRepository.findByReference(request.getReference()).isPresent()) {
            throw new IllegalArgumentException("Transaction reference already exists");
        }

        AppUser user = appUserRepository.findById(request.getUserId())
                .orElseThrow(() -> new EntityNotFoundException("User not found"));

        TransactionRecord transaction = new TransactionRecord(
                request.getReference(),
                user,
                request.getAmount(),
                request.getCurrency(),
                request.getType(),
                "PENDING"
        );

        TransactionRecord saved = transactionRecordRepository.save(transaction);
        return toResponse(saved);
    }

    @Transactional(readOnly = true)
    public TransactionResponse getTransaction(Long id) {
        TransactionRecord tx = transactionRecordRepository.findById(id)
                .orElseThrow(() -> new EntityNotFoundException("Transaction not found"));
        return toResponse(tx);
    }

    @Transactional(readOnly = true)
    public List<TransactionResponse> listTransactionsForUser(Long userId) {
        return transactionRecordRepository.findByUserId(userId).stream()
                .map(this::toResponse)
                .toList();
    }

    public TransactionResponse processTransaction(Long id, String status) {
        TransactionRecord tx = transactionRecordRepository.findById(id)
                .orElseThrow(() -> new EntityNotFoundException("Transaction not found"));
        tx.setStatus(status);
        TransactionRecord saved = transactionRecordRepository.save(tx);
        return toResponse(saved);
    }

    private TransactionResponse toResponse(TransactionRecord tx) {
        return new TransactionResponse(
                tx.getId(),
                tx.getReference(),
                tx.getUser().getId(),
                tx.getAmount(),
                tx.getCurrency(),
                tx.getType(),
                tx.getStatus(),
                tx.getCreatedAt()
        );
    }
}

package com.example.enterprise.controller;

